SELECT document_type, COUNT(*) AS document_count
FROM property_documents
GROUP BY document_type;

SELECT transaction_type, SUM(amount) as total_amount
FROM property_transactions
GROUP BY transaction_type;

SELECT transaction_id, property_id, transaction_date, transaction_type, amount, buyer_id
FROM property_transactions
WHERE buyer_id = 0;

SELECT property_id, image_type, upload_date, MAX(image_size) AS largest_image_size
FROM property_images
GROUP BY property_id, image_type, upload_date;

SELECT COUNT(*) AS transaction_count, SUM(amount) AS total_amount
FROM property_transactions
WHERE transaction_type = 'Sale';

SELECT SUM(tax_amount) AS total_tax_collected
FROM tax_records
WHERE year = 2022;
